                    await next(context);
                    return;
                }

                // Populate the HttpContext user with the claims from the JWT
                context.User = principal;
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Error validating JWT token");
                await next(context);
                return;
            }

            // Call the next middleware in the pipeline
            await next(context);
